Code.Terraform:
```hcl
# シークレットポリシーを制限し、パブリックアクセスをブロックする
resource "aws_secretsmanager_secret_policy" "<example_resource_name>" {
  secret_arn         = "<example_resource_id>"
  block_public_policy = true  # 重大: パブリックポリシーをブロックします
  policy = jsonencode({       # 重大: principal は "*" ではありません
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "arn:aws:iam::<ACCOUNT_ID>:root" }
      Action    = "secretsmanager:GetSecretValue"
      Resource  = "*"
    }]
  })
}
```
